const validLogLevels = [
    "Off" /* LogLevel.Off */,
    "Error" /* LogLevel.Error */,
    "Warn" /* LogLevel.Warn */,
    "Info" /* LogLevel.Info */,
    "Debug" /* LogLevel.Debug */,
    "Trace" /* LogLevel.Trace */,
];
const isLogLevel = (level) => {
    return validLogLevels.includes(level);
};
